function showParsedPreview(data) {
  const container = document.getElementById('parsed-sections');
  document.getElementById('parsed-preview').style.display = 'block';

  let html = '';

  if (data.contact) {
    html += `<div class="parsed-section">
      <h4>📋 Contact Info</h4>
      <p>Name: ${data.contact.name || 'Not found'}</p>
      <p>Location: ${data.contact.location || 'Not found'}</p>
    </div>`;
  }

  if (data.experience && data.experience.length > 0) {
    html += `<div class="parsed-section">
      <h4>💼 Experience (${data.experience.length} positions)</h4>
      ${data.experience.slice(0, 3).map(e => `<p>• ${e.title} at ${e.company}</p>`).join('')}
    </div>`;
  }

  if (data.education && data.education.length > 0) {
    html += `<div class="parsed-section">
      <h4>🎓 Education (${data.education.length} entries)</h4>
      ${data.education.slice(0, 2).map(e => `<p>• ${e.degree || ''} at ${e.institution}</p>`).join('')}
    </div>`;
  }

  if (data.skills && data.skills.length > 0) {
    html += `<div class="parsed-section">
      <h4>💡 Skills (${data.skills.length} found)</h4>
      <p>${data.skills.slice(0, 10).map(s => s.name).join(', ')}</p>
    </div>`;
  }

  container.innerHTML = html;
}

async function applyParsedData() {
  if (!parsedResumeData) return;

  try {
    await apiCall('/candidate/resume/apply', {
      method: 'POST',
      body: JSON.stringify({
        parsed_data: parsedResumeData,
        apply_sections: ['profile', 'experience', 'education', 'skills']
      })
    });

    document.getElementById('parsed-preview').style.display = 'none';
    loadProfile();
    alert('Resume data applied to your profile!');
  } catch (err) {
    alert('Failed to apply resume data');
  }
}

function dismissParsedData() {
  document.getElementById('parsed-preview').style.display = 'none';
  parsedResumeData = null;
}

